/* Get GWorld Instance */static void GetAndLogGWorld()
{
	try
	{
		uint64_t image_base = (uint64_t)GetModuleHandle(nullptr);
		if (!image_base)
			return;

		uint64_t gworld_address = image_base + Offsets::GWorld;

		// Retry loop - GWorld may not be initialized yet
		int attempt = 0;
		int retry_delay_ms = 500;
		int max_attempts = 120; // 60 seconds max
		
		while (true)
		{
			attempt++;
			auto gworld_ptr = reinterpret_cast<UWorld**>(gworld_address);
			auto gworld_value = *gworld_ptr;

			if (gworld_value)
			{
				// Console logging disabled
				// std::stringstream ss;
				// ss << "[SDK::GWorld] 0x" << std::hex << (uint64_t)gworld_value << " (attempt " << attempt << ")";
				// printf("%s\n", ss.str().c_str());
				fflush(stdout);
				return;
			}

			if (attempt >= max_attempts)
			{
				// Console logging disabled
				// printf("[SDK::GWorld] Timeout (NULL after %d attempts)\n", attempt);
				fflush(stdout);
				return;
			}

			Sleep(retry_delay_ms);
		}
	}
	catch (...) {}
}

