// Check if ESP system is fully initialized
extern "C" bool SDK_IsESPInitialized()
{
	try
	{
		// Check if we can access world
		UWorld* World = UWorld::GetWorld();
		if (!World) return false;

		// Check if we can access player controller
		APlayerController* PC = UGameplayStatics::GetPlayerController(World, 0);
		if (!PC) return false;

		// Check if we can access camera manager
		if (!PC->PlayerCameraManager) return false;

		// All checks passed
		return true;
	}
	catch (...)
	{
		return false;
	}
}

// Check if an actor is visible on screen
extern "C" bool SDK_IsActorVisible(AActor* Actor)
{
	try
	{
		if (!Actor) return false;

		// Get screen position using K2_GetActorLocation (SDK-compatible)
		FVector ActorLoc = Actor->K2_GetActorLocation();
		FVector2D ScreenPos = { 0.0f, 0.0f };
		if (!SDK_ProjectWorldToScreen(ActorLoc, &ScreenPos))
			return false;  // Behind camera

		// Get viewport size
		float ViewportX = 0.0f, ViewportY = 0.0f;
		SDK_GetOverlayViewportSize(&ViewportX, &ViewportY);

		// Check if screen position is within viewport bounds (with small margin)
		const float Margin = 50.0f;
		if (ScreenPos.X < -Margin || ScreenPos.X > (ViewportX + Margin))
			return false;
		if (ScreenPos.Y < -Margin || ScreenPos.Y > (ViewportY + Margin))
			return false;

		return true;
	}
	catch (...)
	{
		return false;
	}
}

// Render visibility. Reads RootComponent (AActor+0x130) -> USceneComponent bVisible bit
// (byte at +0x14C, mask 0x20). Used to only target enemies actually being rendered
// (no locking through walls / off-screen / culled actors).
extern "C" bool SDK_IsActorRenderVisible(AActor* Actor)
{
	if (!SDK_IsReadableMemory(Actor, 0x138))
		return false;

	uintptr_t rootComponent = 0;
	if (!SDK_TryReadMemory(reinterpret_cast<const uint8*>(Actor) + 0x130, rootComponent) ||
		!SDK_IsReadableMemory(reinterpret_cast<const void*>(rootComponent + 0x14C), sizeof(uint8)))
		return false;

	uint8 sceneFlags = 0;
	if (!SDK_TryReadMemory(reinterpret_cast<const void*>(rootComponent + 0x14C), sceneFlags))
		return false;

	return (sceneFlags & 0x20) != 0;  // bVisible
}

