// Get bone indices EXACTLY LIKE ZERO1 - read FName from ReferenceSkeleton and match
static std::map<std::string, int32> SDK_GetBoneIndexMapExact(SDK::USkeletalMeshComponent* meshComponent, int32& totalBones)
{
	std::map<std::string, int32> boneMap;
	totalBones = 0;
	
	if (!meshComponent)
		return boneMap;
	
	try
	{
		uint8* meshMem = reinterpret_cast<uint8*>(meshComponent);
		
		// STEP 1: Get USkeletalMesh pointer from MeshComponent (offset 0x480 = 1152 decimal)
		SDK::USkeletalMesh* skelMesh = *(SDK::USkeletalMesh**)(meshMem + 0x480);
		
		if (!skelMesh)
			return boneMap;
		
		uint8* skelMeshMem = reinterpret_cast<uint8*>(skelMesh);
		
		// STEP 2: Get bone array from USkeletalMeshComponent (offsets 0x4B0 and 0x4B8)
		uint8* boneArrayPtr = *(uint8**)(skelMeshMem + 0x4B0);
		int32 boneCount = *(int32*)(skelMeshMem + 0x4B8);
		totalBones = boneCount;
		
		{
			char debugMsg[512];
			snprintf(debugMsg, sizeof(debugMsg), "[BoneArray] Offset 0x4B0: ptr=%p, Offset 0x4B8: count=%d", 
				boneArrayPtr, boneCount);
			SkeletonDebugLog(debugMsg);
		}
		
		if (boneCount <= 0 || boneCount > 500 || !boneArrayPtr)
		{
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "[BoneArray] INVALID: count=%d, ptr=%p", 
				boneCount, boneArrayPtr);
			SkeletonDebugLog(debugMsg);
			return boneMap;
		}
		
		// Each bone in ReferenceSkeleton is 12 bytes (like zero1):
		// [FName BoneName: 4] [ParentIndex: 4] [Flags: 4]
		const int32 BONE_ENTRY_SIZE = 12;  // NOT 20!
		
		
		// EXACTLY LIKE ZERO1: Read ReferenceSkeleton and match known bone names
		// Zero1 approach: read all bones, extract FName, check against KNOWN set
		
		std::vector<std::string> expectedBones = {
			"waist", "spine", "chest", "neck", "head",
			"L_collar", "L_arm", "L_elbow", "L_hand",
			"R_collar", "R_arm", "R_elbow", "R_hand",
			"hip", "L_leg", "L_knee", "L_ankle", "L_toe",
			"R_leg", "R_knee", "R_ankle", "R_toe"
		};
		
		// Each bone entry: 12 bytes (FName:4 + ParentIdx:4 + Flags:4)
		const int32 BONE_ENTRY_SIZE_LOCAL = 12;
		
		int32 skeletonStart = -1;
		int32 matchCount = 0;
		
		// Scan for the skeleton - it should have 22+ bones with valid parents
		for (int32 startPos = 0; startPos < boneCount - 22; startPos++)
		{
			// Try to find 22 bones with sequential parents (a skeleton)
			int32 tempMatches = 0;
			
			for (int32 i = 0; i < 22 && startPos + i < boneCount; i++)
			{
				uint8* boneEntry = boneArrayPtr + ((startPos + i) * BONE_ENTRY_SIZE_LOCAL);
				int32 fname = *(int32*)(boneEntry + 0);
				int32 parentIdx = *(int32*)(boneEntry + 4);
				
				// Valid parent indices for skeleton: -1 (root) or sequential
				if (parentIdx >= -1 && parentIdx < (startPos + i))
				{
					tempMatches++;
				}
			}
			
			if (tempMatches >= 20)  // Good enough match
			{
				skeletonStart = startPos;
				matchCount = tempMatches;
				{
					char debugMsg[256];
					snprintf(debugMsg, sizeof(debugMsg), "Found skeleton block at index %d with %d valid bones", skeletonStart, matchCount);
					SkeletonDebugLog(debugMsg);
				}
				break;
			}
		}
		
		if (skeletonStart >= 0)
		{
			// Read the 22 bones from this position and use expected names
			for (int32 i = 0; i < 22; i++)
			{
				if (skeletonStart + i >= boneCount)
					break;
					
				boneMap[expectedBones[i]] = skeletonStart + i;
				
				uint8* boneEntry = boneArrayPtr + ((skeletonStart + i) * BONE_ENTRY_SIZE_LOCAL);
				int32 fname = *(int32*)(boneEntry + 0);
				int32 parentIdx = *(int32*)(boneEntry + 4);
				
				char debugMsg[256];
				snprintf(debugMsg, sizeof(debugMsg), "Skeleton[%d] = %s (FName=%d, Parent=%d)", i, expectedBones[i].c_str(), fname, parentIdx);
				SkeletonDebugLog(debugMsg);
			}
		}
		
		if (!boneMap.empty())
		{
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "GetBoneIndexMapExact: Matched %d bone names", (int32)boneMap.size());
			SkeletonDebugLog(debugMsg);
		}
		
		return boneMap;
	}
	catch (...)
	{
		SkeletonDebugLog("GetBoneIndexMapExact: Exception occurred");
		return boneMap;
	}
}

// Convert quaternion + translation + scale to 4x4 matrix (EXACTLY LIKE ZERO1)
static void FTransformToMatrix(const FQuat& rotation, const FVector& translation, const FVector& scale, float matrix[16])
{
	// Quaternion to rotation matrix
	float x = rotation.X, y = rotation.Y, z = rotation.Z, w = rotation.W;
	float x2 = x + x, y2 = y + y, z2 = z + z;
	float xx = x * x2, xy = x * y2, xz = x * z2;
	float yy = y * y2, yz = y * z2, zz = z * z2;
	float wx = w * x2, wy = w * y2, wz = w * z2;
	
	// Rotation matrix with scale
	matrix[0] = (1.0f - (yy + zz)) * scale.X;
	matrix[1] = (xy + wz) * scale.X;
	matrix[2] = (xz - wy) * scale.X;
	matrix[3] = 0.0f;
	
	matrix[4] = (xy - wz) * scale.Y;
	matrix[5] = (1.0f - (xx + zz)) * scale.Y;
	matrix[6] = (yz + wx) * scale.Y;
	matrix[7] = 0.0f;
	
	matrix[8] = (xz + wy) * scale.Z;
	matrix[9] = (yz - wx) * scale.Z;
	matrix[10] = (1.0f - (xx + yy)) * scale.Z;
	matrix[11] = 0.0f;
	
	// Translation
	matrix[12] = translation.X;
	matrix[13] = translation.Y;
	matrix[14] = translation.Z;
	matrix[15] = 1.0f;
}

// Matrix multiplication: m1 * m2
static void MatrixMultiply(const float m1[16], const float m2[16], float result[16])
{
	for (int i = 0; i < 4; i++)
	{
		for (int j = 0; j < 4; j++)
		{
			result[i * 4 + j] = m1[i * 4 + 0] * m2[0 * 4 + j] +
			                    m1[i * 4 + 1] * m2[1 * 4 + j] +
			                    m1[i * 4 + 2] * m2[2 * 4 + j] +
			                    m1[i * 4 + 3] * m2[3 * 4 + j];
		}
	}
}

// Read ComponentToWorld matrix from component (EXACTLY LIKE ZERO1)
static void GetComponentToWorldMatrix(SDK::USkeletalMeshComponent* meshComponent, float matrix[16])
{
	// ComponentToWorld is FTransform at offset 0x1C0 (448 decimal)
	uint8* componentMem = reinterpret_cast<uint8*>(meshComponent);
	uint8* transformData = componentMem + 0x1C0;
	
	// Read rotation quaternion
	FQuat rot;
	rot.X = *(float*)(transformData + 0);
	rot.Y = *(float*)(transformData + 4);
	rot.Z = *(float*)(transformData + 8);
	rot.W = *(float*)(transformData + 12);
	
	// Read translation
	FVector trans;
	trans.X = *(float*)(transformData + 16);
	trans.Y = *(float*)(transformData + 20);
	trans.Z = *(float*)(transformData + 24);
	
	// Read scale (default 1.0)
	FVector scl;
	scl.X = *(float*)(transformData + 32);
	scl.Y = *(float*)(transformData + 36);
	scl.Z = *(float*)(transformData + 40);
	
	// Convert to matrix
	FTransformToMatrix(rot, trans, scl, matrix);
}

// Extract 3D bone positions from skeletal mesh component (like zero1)
static std::vector<FVector> SDK_GetBonePositions(SDK::AActor* character)
{
	std::vector<FVector> bonePositions;
	bonePositions.resize(22);  // 22 bones
	
	if (!character)
	{
		SkeletonDebugLog("GetBonePositions: Character is null");
		return bonePositions;
	}
	
	try
	{
		// Get the skeletal mesh component using offset (verified against SDK)
		uint8* characterMem = reinterpret_cast<uint8*>(character);
		SDK::USkeletalMeshComponent* meshComponent = *(SDK::USkeletalMeshComponent**)(characterMem + 0x280);
		
		if (!meshComponent)
		{
			SkeletonDebugLog("[ERREUR] GetBonePositions: MeshComponent is null");
			FVector actorPos = character->K2_GetActorLocation();
			for (int i = 0; i < 22; i++)
				bonePositions[i] = actorPos;
			return bonePositions;
		}
		
		// Validate meshComponent pointer is readable
		if (IsBadReadPtr(meshComponent, sizeof(void*)))
		{
			SkeletonDebugLog("[ERREUR] GetBonePositions: MeshComponent pointer is invalid/unreadable");
			FVector actorPos = character->K2_GetActorLocation();
			for (int i = 0; i < 22; i++)
				bonePositions[i] = actorPos;
			return bonePositions;
		}
		
		SkeletonDebugLog("[OK] MeshComponent retrieved and validated");
		
		// Get total bone count using SDK function (may be 0 for some characters, so not reliable)
		int32 totalBoneCount = 0;
		try
		{
			totalBoneCount = meshComponent->GetNumBones();
		}
		catch (...)
		{
			totalBoneCount = 0;
		}
		{
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "[INFO] GetNumBones() returned: %d", totalBoneCount);
			SkeletonDebugLog(debugMsg);
		}
		
		// NOTE: GetNumBones() returns 0 for non-Mirko characters, so we can't rely on it
		// We'll check the actual ReferenceSkeleton later
		
		// Get ComponentToWorld using SDK function K2_GetComponentToWorld()
		struct FTransform componentToWorld;
		memset(&componentToWorld, 0, sizeof(FTransform));
		try
		{
			componentToWorld = meshComponent->K2_GetComponentToWorld();
		}
		catch (...)
		{
			SkeletonDebugLog("[ERREUR] K2_GetComponentToWorld() threw exception");
		}
		{
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "[OK] ComponentToWorld: pos=(%.1f, %.1f, %.1f)", 
				componentToWorld.Translation.X, componentToWorld.Translation.Y, componentToWorld.Translation.Z);
			SkeletonDebugLog(debugMsg);
		}
		
		SkeletonDebugLog("[INFO] Building bone name map using ReferenceSkeleton (LIKE ZERO1)...");
		
		// Bone names to extract (like zero1)
		std::vector<std::string> boneNamesToFind = {
			"waist", "spine", "chest", "neck", "head",
			"L_collar", "L_arm", "L_elbow", "L_hand",
			"R_collar", "R_arm", "R_elbow", "R_hand",
			"hip", "L_leg", "L_knee", "L_ankle", "L_toe",
			"R_leg", "R_knee", "R_ankle", "R_toe"
		};
		
		// Get USkeletalMesh pointer
		uint8* componentMem = reinterpret_cast<uint8*>(meshComponent);
		SDK::USkeletalMesh* skeletalMesh = *(SDK::USkeletalMesh**)(componentMem + 0x480);
		
		if (!skeletalMesh)
		{
			SkeletonDebugLog("[ERREUR] USkeletalMesh is null");
			return bonePositions;
		}
		
		// Read ReferenceSkeleton from USkeletalMesh (offset 0x1D0 like zero1)
		std::map<std::string, int32> boneMap;
		uint8* meshMem = reinterpret_cast<uint8*>(skeletalMesh);
		
		// ReferenceSkeleton is at 0x1D0 (contains: array address, count)
		void* refSkeletonArray = *(void**)(meshMem + 0x1D0);
		int32 refSkeletonCount = *(int32*)(meshMem + 0x1D8);
		
		if (!refSkeletonArray || refSkeletonCount <= 0 || refSkeletonCount > 500)
		{
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "[ERREUR] Invalid ReferenceSkeleton: count=%d", refSkeletonCount);
			SkeletonDebugLog(debugMsg);
			return bonePositions;
		}
		
		char debugMsg[256];
		snprintf(debugMsg, sizeof(debugMsg), "[OK] ReferenceSkeleton: count=%d", refSkeletonCount);
		SkeletonDebugLog(debugMsg);
		
		// Convert target bone names to FName for comparison (EXACTLY LIKE ZERO1)
		std::vector<SDK::FName> targetFNames;
		for (const auto& boneName : boneNamesToFind)
		{
			// Convert string to FName using SDK utilities
			SDK::FName fName = BasicFilesImpleUtils::StringToName(
				std::wstring(boneName.begin(), boneName.end()).c_str()
			);
			targetFNames.push_back(fName);
		}
		
		// Iterate through ReferenceSkeleton and match FName to our target bones
		snprintf(debugMsg, sizeof(debugMsg), "[INFO] Searching for %zu bones in ReferenceSkeleton (count=%d)...", 
			boneNamesToFind.size(), refSkeletonCount);
		SkeletonDebugLog(debugMsg);
		
		for (int32 i = 0; i < refSkeletonCount && i < 500; i++)
		{
			// Get the actual bone name from the skeleton
			SDK::FName boneFName;
			try
			{
				boneFName = meshComponent->GetBoneName(i);
			}
			catch (...)
			{
				continue;  // Skip if can't get bone name
			}
			
			// Try to match with our target bones
			for (size_t targetIdx = 0; targetIdx < targetFNames.size(); targetIdx++)
			{
				// Compare FName directly
				if (boneFName.ComparisonIndex == targetFNames[targetIdx].ComparisonIndex &&
					boneFName.Number == targetFNames[targetIdx].Number)
				{
					// Found a match!
					boneMap[boneNamesToFind[targetIdx]] = i;
					snprintf(debugMsg, sizeof(debugMsg), 
						"[OK] BoneMap: '%s' (FName %d.%d) -> index %d", 
						boneNamesToFind[targetIdx].c_str(), 
						boneFName.ComparisonIndex, boneFName.Number, i);
					SkeletonDebugLog(debugMsg);
					break;
				}
			}
		}
		
		snprintf(debugMsg, sizeof(debugMsg), "[INFO] BoneMap complete: found %zu bones", boneMap.size());
		SkeletonDebugLog(debugMsg);
		
		SkeletonDebugLog("[INFO] BoneMap created. Extracting 22 bones...");
		
		// Extract bones using old offsets (0x4B0, 0x4B8, 0x4C0, 0x4C8)
		void* boneArrayPtr = nullptr;
		int32 boneArrayCount = 0;
		
		try
		{
			// Log the component memory address
			snprintf(debugMsg, sizeof(debugMsg), "[DEBUG] componentMem address: %p", componentMem);
			SkeletonDebugLog(debugMsg);
			
			// Log offsets we're about to read
			snprintf(debugMsg, sizeof(debugMsg), "[DEBUG] Reading bone array pointer from offset 0x4B0");
			SkeletonDebugLog(debugMsg);
			
			// Try offset 0x4B0 for bone array pointer
			uint8* boneArrayPtrAddr = componentMem + 0x4B0;
			snprintf(debugMsg, sizeof(debugMsg), "[DEBUG] boneArrayPtrAddr (0x%p + 0x4B0) = %p", componentMem, boneArrayPtrAddr);
			SkeletonDebugLog(debugMsg);
			
			boneArrayPtr = *(void**)(boneArrayPtrAddr);
			snprintf(debugMsg, sizeof(debugMsg), "[DEBUG] boneArrayPtr value from 0x4B0: %p", boneArrayPtr);
			SkeletonDebugLog(debugMsg);
			
			// Try offset 0x4B8 for bone array count
			snprintf(debugMsg, sizeof(debugMsg), "[DEBUG] Reading bone array count from offset 0x4B8");
			SkeletonDebugLog(debugMsg);
			
			uint8* boneArrayCountAddr = componentMem + 0x4B8;
			snprintf(debugMsg, sizeof(debugMsg), "[DEBUG] boneArrayCountAddr (0x%p + 0x4B8) = %p", componentMem, boneArrayCountAddr);
			SkeletonDebugLog(debugMsg);
			
			boneArrayCount = *(int32*)(boneArrayCountAddr);
			snprintf(debugMsg, sizeof(debugMsg), "[DEBUG] boneArrayCount value from 0x4B8: %d", boneArrayCount);
			SkeletonDebugLog(debugMsg);
			
			// Detailed validation
			snprintf(debugMsg, sizeof(debugMsg), "[INFO] Bone array from old offsets: ptr=%p, count=%d (valid=%s)", 
				boneArrayPtr, boneArrayCount, 
				(boneArrayPtr && boneArrayCount > 0 && boneArrayCount <= 500) ? "YES" : "NO");
			SkeletonDebugLog(debugMsg);
		}
		catch (...)
		{
			SkeletonDebugLog("[ERREUR] Exception reading old bone array offsets (0x4B0/0x4B8)");
			snprintf(debugMsg, sizeof(debugMsg), "[DEBUG] Last known state: ptr=%p, count=%d", boneArrayPtr, boneArrayCount);
			SkeletonDebugLog(debugMsg);
		}
		
		// Validate bone array is available and reasonable
		if (!boneArrayPtr || boneArrayCount <= 0 || boneArrayCount > 500)
		{
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "[WARN] Bone array invalid (ptr=%p, count=%d). Using FALLBACK: actor position for all bones", 
				boneArrayPtr, boneArrayCount);
			SkeletonDebugLog(debugMsg);
			
			// FALLBACK: Use actor position for all bones
			FVector actorPos = character->K2_GetActorLocation();
			for (int boneIdx = 0; boneIdx < 22; boneIdx++)
			{
				bonePositions[boneIdx] = actorPos;
			}
			
			SkeletonDebugLog("[INFO] Fallback: Using actor position for all 22 bones");
			return bonePositions;
		}
		
		// Extract bones using the map and old offsets (EXACTLY LIKE BEFORE)
		int bonePositionIdx = 0;
		for (const auto& boneName : boneNamesToFind)
		{
			// Get the real bone index from map
			int32 boneIndex = -1;
			if (boneMap.find(boneName) != boneMap.end())
			{
				boneIndex = boneMap[boneName];
			}
			else
			{
				// Fallback: assume sequential 0-21
				boneIndex = bonePositionIdx;
			}
			
			if (boneIndex >= 0 && boneIndex < boneArrayCount)
			{
				try
				{
					// SAFETY: Verify boneArrayPtr is valid before dereferencing
					if (!boneArrayPtr || IsBadReadPtr(boneArrayPtr, 1))
					{
						char debugMsg[256];
						snprintf(debugMsg, sizeof(debugMsg), "[ERREUR] Invalid boneArrayPtr: %p", boneArrayPtr);
						SkeletonDebugLog(debugMsg);
						bonePositions[bonePositionIdx] = character->K2_GetActorLocation();
						bonePositionIdx++;
						continue;
					}
					
					// OLD OFFSETS: 0x4C0 and 0x4C8 point to FTransform in bone array
					// Each bone is likely 48 bytes (FTransform size)
					uint8* boneDataPtr = reinterpret_cast<uint8*>(boneArrayPtr) + (boneIndex * 48);
					
					// SAFETY: Verify boneDataPtr is readable before accessing
					if (IsBadReadPtr(boneDataPtr, 48))
					{
						char debugMsg[256];
						snprintf(debugMsg, sizeof(debugMsg), "[ERREUR] Invalid bone data at ptr: %p (offset from %p)", boneDataPtr, boneArrayPtr);
						SkeletonDebugLog(debugMsg);
						bonePositions[bonePositionIdx] = character->K2_GetActorLocation();
						bonePositionIdx++;
						continue;
					}
					
					// Extract quaternion (16 bytes) and position (12 bytes) from FTransform
					FQuat rotation;
					rotation.X = *(float*)(boneDataPtr + 0);
					rotation.Y = *(float*)(boneDataPtr + 4);
					rotation.Z = *(float*)(boneDataPtr + 8);
					rotation.W = *(float*)(boneDataPtr + 12);
					
					FVector localPos;
					localPos.X = *(float*)(boneDataPtr + 16);
					localPos.Y = *(float*)(boneDataPtr + 20);
					localPos.Z = *(float*)(boneDataPtr + 24);
					
					FVector scale;
					scale.X = *(float*)(boneDataPtr + 32);
					scale.Y = *(float*)(boneDataPtr + 36);
					scale.Z = *(float*)(boneDataPtr + 40);
					
					// Convert to world position using ComponentToWorld
					float boneMatrix[16];
					FTransformToMatrix(rotation, localPos, scale, boneMatrix);
					
					float componentToWorldMatrix[16];
					struct FTransform componentToWorld = meshComponent->K2_GetComponentToWorld();
					FTransformToMatrix(componentToWorld.Rotation, componentToWorld.Translation, componentToWorld.Scale3D, componentToWorldMatrix);
					
					float worldMatrix[16];
					MatrixMultiply(boneMatrix, componentToWorldMatrix, worldMatrix);
					
					FVector worldPos;
					worldPos.X = worldMatrix[12];
					worldPos.Y = worldMatrix[13];
					worldPos.Z = worldMatrix[14];
					
					bonePositions[bonePositionIdx] = worldPos;
					
					char debugMsg[256];
					snprintf(debugMsg, sizeof(debugMsg), "[OK] Bone '%s' (idx=%d): world=(%.1f, %.1f, %.1f)", 
						boneName.c_str(), boneIndex, worldPos.X, worldPos.Y, worldPos.Z);
					SkeletonDebugLog(debugMsg);
				}
				catch (const std::exception& ex)
				{
					char debugMsg[256];
					snprintf(debugMsg, sizeof(debugMsg), "[ERREUR] Exception on bone '%s': %s", boneName.c_str(), ex.what());
					SkeletonDebugLog(debugMsg);
					bonePositions[bonePositionIdx] = character->K2_GetActorLocation();
				}
				catch (...)
				{
					char debugMsg[256];
					snprintf(debugMsg, sizeof(debugMsg), "[ERREUR] Unknown exception extracting bone '%s'", boneName.c_str());
					SkeletonDebugLog(debugMsg);
					bonePositions[bonePositionIdx] = character->K2_GetActorLocation();
				}
			}
			else
			{
				char debugMsg[256];
				snprintf(debugMsg, sizeof(debugMsg), "[WARN] Bone '%s': Invalid bone index %d (count=%d)", 
					boneName.c_str(), boneIndex, boneArrayCount);
				SkeletonDebugLog(debugMsg);
				bonePositions[bonePositionIdx] = character->K2_GetActorLocation();
			}
			
			bonePositionIdx++;
		}
		
		SkeletonDebugLog("[OK] Successfully extracted all 22 bones using SDK functions");
		return bonePositions;
	}
	catch (const std::exception& ex)
	{
		char debugMsg[256];
		snprintf(debugMsg, sizeof(debugMsg), "[ERREUR] GetBonePositions: Exception - %s", ex.what());
		SkeletonDebugLog(debugMsg);
		
		FVector actorPos = character->K2_GetActorLocation();
		for (int i = 0; i < 22; i++)
			bonePositions[i] = actorPos;
		return bonePositions;
	}
	catch (...)
	{
		SkeletonDebugLog("[ERREUR] GetBonePositions: Unknown exception occurred");
		FVector actorPos = character->K2_GetActorLocation();
		for (int i = 0; i < 22; i++)
			bonePositions[i] = actorPos;
		return bonePositions;
	}
}

// Project bones to 2D and create Bones structure (like zero1)
static Bones SDK_GetBones(SDK::AActor* character, FVector* OutHeadWorldPosition)
{
	Bones bones = {};  // Default empty bones

	if (OutHeadWorldPosition)
		*OutHeadWorldPosition = FVector(0, 0, 0);
	
	if (!character)
	{
		SkeletonDebugLog("GetBones: Character is null");
		return bones;
	}
	
	try
	{
		// Get 3D bone positions
		std::vector<FVector> bonePositions = SDK_GetBonePositions(character);
		
		if (bonePositions.empty())
		{
			SkeletonDebugLog("GetBones: Empty bone positions");
			return bones;
		}

		if (OutHeadWorldPosition && bonePositions.size() > 4)
			*OutHeadWorldPosition = bonePositions[4];
		
		ImVec2 screenSize = ImGui::GetIO().DisplaySize;
		{
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "Screen size: %.0f x %.0f", screenSize.x, screenSize.y);
			SkeletonDebugLog(debugMsg);
		}
		
		// Project all bones to screen space
		// bonePositions order: waist(0), spine(1), chest(2), neck(3), head(4), L_collar(5-8), R_collar(9-12), hip(13), L_leg(14-17), R_leg(18-21)
		FVector2D screenPos = {0.0f, 0.0f};
		int validBones = 0;  // Count bones that project successfully
		
		// Head (from bonePositions[4])
		if (SDK_ProjectWorldToScreen(bonePositions[4], &screenPos))
		{
			if (screenPos.X > 0 && screenPos.Y > 0 && screenPos.X < screenSize.x && screenPos.Y < screenSize.y)
			{
				bones.Head.x = screenPos.X;
				bones.Head.y = screenPos.Y;
				validBones++;
				char debugMsg[256];
				snprintf(debugMsg, sizeof(debugMsg), "Head: screen=(%.1f, %.1f) VALID", screenPos.X, screenPos.Y);
				SkeletonDebugLog(debugMsg);
			}
			else
			{
				char debugMsg[256];
				snprintf(debugMsg, sizeof(debugMsg), "Head: screen=(%.1f, %.1f) OUT OF BOUNDS", screenPos.X, screenPos.Y);
				SkeletonDebugLog(debugMsg);
			}
		}
		else
			SkeletonDebugLog("Head: Projection failed");
		
		// Neck (from bonePositions[3])
		if (SDK_ProjectWorldToScreen(bonePositions[3], &screenPos))
		{
			bones.Neck.x = screenPos.X;
			bones.Neck.y = screenPos.Y;
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "Neck: screen=(%.1f, %.1f) VALID", screenPos.X, screenPos.Y);
			SkeletonDebugLog(debugMsg);
			validBones++;
		}
		else
			SkeletonDebugLog("Neck: Projection failed");
		
		// Spine3 (Chest from bonePositions[2])
		if (SDK_ProjectWorldToScreen(bonePositions[2], &screenPos))
		{
			bones.Spine3.x = screenPos.X;
			bones.Spine3.y = screenPos.Y;
			validBones++;
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "Spine3: screen=(%.1f, %.1f)", screenPos.X, screenPos.Y);
			SkeletonDebugLog(debugMsg);
		}
		else
			SkeletonDebugLog("Spine3: Projection failed");
		
		// Spine2 (Spine from bonePositions[1])
		if (SDK_ProjectWorldToScreen(bonePositions[1], &screenPos))
		{
			bones.Spine2.x = screenPos.X;
			bones.Spine2.y = screenPos.Y;
			validBones++;
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "Spine2: screen=(%.1f, %.1f)", screenPos.X, screenPos.Y);
			SkeletonDebugLog(debugMsg);
		}
		else
			SkeletonDebugLog("Spine2: Projection failed");
		
		// Spine1 (Waist from bonePositions[0]) - EXACT COMME ZERO1
		if (SDK_ProjectWorldToScreen(bonePositions[0], &screenPos))
		{
			bones.Spine1.x = screenPos.X;
			bones.Spine1.y = screenPos.Y;
			validBones++;
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "Spine1: screen=(%.1f, %.1f)", screenPos.X, screenPos.Y);
			SkeletonDebugLog(debugMsg);
		}
		else
			SkeletonDebugLog("Spine1: Projection failed");
		
		// Spine0 (Hip from bonePositions[13]) - EXACT COMME ZERO1
		if (SDK_ProjectWorldToScreen(bonePositions[13], &screenPos))
		{
			bones.Spine0.x = screenPos.X;
			bones.Spine0.y = screenPos.Y;
			validBones++;
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "Spine0: screen=(%.1f, %.1f)", screenPos.X, screenPos.Y);
			SkeletonDebugLog(debugMsg);
		}
		else
			SkeletonDebugLog("Spine0: Projection failed");
		
		// Left arm (bonePositions[5-8]: L_collar, L_arm, L_elbow, L_hand)
		if (SDK_ProjectWorldToScreen(bonePositions[5], &screenPos))
		{
			bones.LClavicle.x = screenPos.X;
			bones.LClavicle.y = screenPos.Y;
			validBones++;
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "LClavicle: screen=(%.1f, %.1f)", screenPos.X, screenPos.Y);
			SkeletonDebugLog(debugMsg);
		}
		if (SDK_ProjectWorldToScreen(bonePositions[6], &screenPos))
		{
			bones.LUpperArm.x = screenPos.X;
			bones.LUpperArm.y = screenPos.Y;
			validBones++;
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "LUpperArm: screen=(%.1f, %.1f)", screenPos.X, screenPos.Y);
			SkeletonDebugLog(debugMsg);
		}
		if (SDK_ProjectWorldToScreen(bonePositions[7], &screenPos))
		{
			bones.LForeArm.x = screenPos.X;
			bones.LForeArm.y = screenPos.Y;
			validBones++;
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "LForeArm: screen=(%.1f, %.1f)", screenPos.X, screenPos.Y);
			SkeletonDebugLog(debugMsg);
		}
		if (SDK_ProjectWorldToScreen(bonePositions[8], &screenPos))
		{
			bones.LHand.x = screenPos.X;
			bones.LHand.y = screenPos.Y;
			validBones++;
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "LHand: screen=(%.1f, %.1f)", screenPos.X, screenPos.Y);
			SkeletonDebugLog(debugMsg);
		}
		
		// Right arm (bonePositions[9-12]: R_collar, R_arm, R_elbow, R_hand)
		if (SDK_ProjectWorldToScreen(bonePositions[9], &screenPos))
		{
			bones.RClavicle.x = screenPos.X;
			bones.RClavicle.y = screenPos.Y;
			validBones++;
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "RClavicle: screen=(%.1f, %.1f)", screenPos.X, screenPos.Y);
			SkeletonDebugLog(debugMsg);
		}
		if (SDK_ProjectWorldToScreen(bonePositions[10], &screenPos))
		{
			bones.RUpperArm.x = screenPos.X;
			bones.RUpperArm.y = screenPos.Y;
			validBones++;
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "RUpperArm: screen=(%.1f, %.1f)", screenPos.X, screenPos.Y);
			SkeletonDebugLog(debugMsg);
		}
		if (SDK_ProjectWorldToScreen(bonePositions[11], &screenPos))
		{
			bones.RForeArm.x = screenPos.X;
			bones.RForeArm.y = screenPos.Y;
			validBones++;
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "RForeArm: screen=(%.1f, %.1f)", screenPos.X, screenPos.Y);
			SkeletonDebugLog(debugMsg);
		}
		if (SDK_ProjectWorldToScreen(bonePositions[12], &screenPos))
		{
			bones.RHand.x = screenPos.X;
			bones.RHand.y = screenPos.Y;
			validBones++;
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "RHand: screen=(%.1f, %.1f)", screenPos.X, screenPos.Y);
			SkeletonDebugLog(debugMsg);
		}
		
		// Left leg (bonePositions[14-17]: L_leg, L_knee, L_ankle, L_toe)
		if (SDK_ProjectWorldToScreen(bonePositions[14], &screenPos))
		{
			bones.LTight.x = screenPos.X;
			bones.LTight.y = screenPos.Y;
			validBones++;
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "LTight: screen=(%.1f, %.1f)", screenPos.X, screenPos.Y);
			SkeletonDebugLog(debugMsg);
		}
		if (SDK_ProjectWorldToScreen(bonePositions[15], &screenPos))
		{
			bones.LCalf.x = screenPos.X;
			bones.LCalf.y = screenPos.Y;
			validBones++;
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "LCalf: screen=(%.1f, %.1f)", screenPos.X, screenPos.Y);
			SkeletonDebugLog(debugMsg);
		}
		if (SDK_ProjectWorldToScreen(bonePositions[16], &screenPos))
		{
			bones.LFoot.x = screenPos.X;
			bones.LFoot.y = screenPos.Y;
			validBones++;
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "LFoot: screen=(%.1f, %.1f)", screenPos.X, screenPos.Y);
			SkeletonDebugLog(debugMsg);
		}
		if (SDK_ProjectWorldToScreen(bonePositions[17], &screenPos))
		{
			bones.LToe.x = screenPos.X;
			bones.LToe.y = screenPos.Y;
			validBones++;
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "LToe: screen=(%.1f, %.1f)", screenPos.X, screenPos.Y);
			SkeletonDebugLog(debugMsg);
		}
		
		// Right leg (bonePositions[18-21]: R_leg, R_knee, R_ankle, R_toe)
		if (SDK_ProjectWorldToScreen(bonePositions[18], &screenPos))
		{
			bones.RTight.x = screenPos.X;
			bones.RTight.y = screenPos.Y;
			validBones++;
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "RTight: screen=(%.1f, %.1f)", screenPos.X, screenPos.Y);
			SkeletonDebugLog(debugMsg);
		}
		if (SDK_ProjectWorldToScreen(bonePositions[19], &screenPos))
		{
			bones.RCalf.x = screenPos.X;
			bones.RCalf.y = screenPos.Y;
			validBones++;
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "RCalf: screen=(%.1f, %.1f)", screenPos.X, screenPos.Y);
			SkeletonDebugLog(debugMsg);
		}
		if (SDK_ProjectWorldToScreen(bonePositions[20], &screenPos))
		{
			bones.RFoot.x = screenPos.X;
			bones.RFoot.y = screenPos.Y;
			validBones++;
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "RFoot: screen=(%.1f, %.1f)", screenPos.X, screenPos.Y);
			SkeletonDebugLog(debugMsg);
		}
		if (SDK_ProjectWorldToScreen(bonePositions[21], &screenPos))
		{
			bones.RToe.x = screenPos.X;
			bones.RToe.y = screenPos.Y;
			validBones++;
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "RToe: screen=(%.1f, %.1f)", screenPos.X, screenPos.Y);
			SkeletonDebugLog(debugMsg);
		}
		
		{
			char debugMsg[256];
			snprintf(debugMsg, sizeof(debugMsg), "GetBones: %d valid bones projected to screen", validBones);
			SkeletonDebugLog(debugMsg);
		}
		
		return bones;
	}
	catch (...)
	{
		SkeletonDebugLog("GetBones: Exception occurred");
		return bones;
	}
}

static void SDK_RefreshCachedActorFrameData()
{
	const bool refreshSkeleton = SDK_ShouldCacheSkeletonData();

	std::lock_guard<std::mutex> lock(g_ActorCacheMutex);
	for (CachedActor& cachedActor : g_ActorsForRendering)
	{
		AActor* actor = cachedActor.ActorPtr;
		if (!actor || !SDK_IsReadableActor(actor) || actor->IsDefaultObject())
			continue;

		try
		{
			cachedActor.Position = actor->K2_GetActorLocation();
		}
		catch (...)
		{
			continue;
		}

		if (!refreshSkeleton)
			continue;

		const bool shouldRefreshSkeleton =
			((SDK_IsBattleCharacterClassName(cachedActor.ClassName) &&
			  cachedActor.TeamId != 255 &&
			  !cachedActor.IsMySelf) ||
			 SDK_IsOutGameCharacterClassName(cachedActor.ClassName));
		if (!shouldRefreshSkeleton)
			continue;

		try
		{
			FVector headWorldPosition = FVector(0, 0, 0);
			Bones frameSkeleton = SDK_GetBones(actor, &headWorldPosition);
			cachedActor.Skeleton = frameSkeleton;
			cachedActor.HasValidSkeleton = frameSkeleton.Head.x > 0.0f && frameSkeleton.Head.y > 0.0f;
			cachedActor.HeadWorldPosition = headWorldPosition;
			cachedActor.HasValidHeadWorldPosition =
				cachedActor.HasValidSkeleton &&
				SDK_IsValidHeadWorldPosition(actor, cachedActor.HeadWorldPosition);
		}
		catch (...)
		{
			cachedActor.HasValidSkeleton = false;
			cachedActor.HeadWorldPosition = FVector(0, 0, 0);
			cachedActor.HasValidHeadWorldPosition = false;
		}
	}
}

// ===== DRAWING FUNCTIONS FOR ESP =====

/**
 * @brief Update actor cache with throttling (like zero1's 200ms enumeration)
 * 
 * Enumerates actors only if ENUMERATION_THROTTLE_MS has passed since last enumeration.
 * Uses double-buffering: g_ActorsToProcess is filled, then swapped with g_ActorsForRendering.
 */
static void SDK_UpdateActorCache()
{
	uint64_t currentTime = GetCurrentTimeMs();
	
	// Check if it's time to enumerate (200ms throttle like zero1)
	if ((currentTime - g_LastEnumerationTime) < ENUMERATION_THROTTLE_MS)
	{
		// Reuse cached actors from last enumeration - NO NEW ENUMERATION NEEDED
		// Render thread reads from g_ActorsForRendering which was filled 200ms ago
		return;
	}
	
	// 200ms passed - time to enumerate actors (heavyweight operation in separate logic)
	g_LastEnumerationTime = currentTime;
	
	try
	{
		// Get world
		UWorld* World = UWorld::GetWorld();
		if (!World || !World->PersistentLevel)
			return;
		
		// Enumerate actors (this is the expensive operation, but only every 200ms)
		const TArray<AActor*>& AllActors = World->PersistentLevel->Actors;
		
		// Clear temporary buffers
		std::vector<CachedActor> newActorList;
		std::vector<CachedActor> newItemList;  // SEPARATE LIST FOR ITEMS
		newActorList.reserve(100);  // Pre-allocate for typical count
		newItemList.reserve(50);    // Pre-allocate for typical items count
		
		AActor* localPlayerPawn = nullptr;
		try
		{
			APlayerController* playerController = SDK_GetPlayerController();
			if (playerController)
				localPlayerPawn = playerController->Pawn;

			if (localPlayerPawn && SDK_IsReadableActor(localPlayerPawn, OFFSET_TEAMID + sizeof(uint16)))
			{
				const uint8 myTeam = GetCharacterTeamId(localPlayerPawn);
				if (myTeam != 255)
				{
					g_MyTeamId = myTeam;
					g_LastLocalPlayerCharacter = localPlayerPawn;
				}
			}
		}
		catch (...)
		{
			localPlayerPawn = nullptr;
		}

		for (int i = 0; i < AllActors.Num(); i++)
		{
			AActor* Actor = AllActors[i];
			
			// Safety: Skip null or default objects
			if (!Actor) continue;
			if (Actor->IsDefaultObject()) continue;
			
			// Additional safety: Validate Actor pointer is readable before accessing
			if (IsBadReadPtr(Actor, sizeof(void*)))
			{
				continue;  // Skip if Actor pointer is invalid/unreadable
			}
			
			// Additional safety: Try to access Class - if it crashes, skip
			SDK::UClass* ActorClass = nullptr;
			try
			{
				ActorClass = Actor->Class;
				if (!ActorClass) continue;
			}
			catch (...)
			{
				continue;  // Skip if Class is inaccessible
			}
			
			// Get class name (safe access)
			std::string ClassName = "";
			try
			{
				// Validate ActorClass is readable
				if (IsBadReadPtr(ActorClass, sizeof(void*)))
				{
					continue;  // Skip if ActorClass pointer is invalid
				}
				
				// Try to get the name
				ClassName = ActorClass->GetName();
				if (ClassName.empty()) continue;  // Skip if name is empty
			}
			catch (...)
			{
				continue;
			}
			
			const bool isOutGameCharacter = SDK_IsOutGameCharacterClassName(ClassName);
			const bool isBattleCharacter = SDK_IsBattleCharacterClassName(ClassName);
			const bool isSubCharacter = (ClassName == "SubCharacter");
			const bool isCharacter = isOutGameCharacter || isBattleCharacter || isSubCharacter;
			
			bool isNPC = (ClassName == "NPCCitizen");
			
			// Check for Items (23 item classes)
			bool isItem = (ClassName == "BP_Su001_C" ||  // HP Recovery Drink (Small)
						   ClassName == "BP_Su002_C" ||  // HP Recovery Drink (Large)
						   ClassName == "BP_Su003_C" ||  // Team HP Recovery Kit
						   ClassName == "BP_Su004_C" ||  // GP Recovery Drink (Small)
						   ClassName == "BP_Su005_C" ||  // GP Recovery Drink (Large)
						   ClassName == "BP_Su006_C" ||  // Team GP Recovery Kit
						   ClassName == "BP_Su007_C" ||  // Full Support Drink
						   ClassName == "BP_Su008_C" ||  // Item Bag (Small)
						   ClassName == "BP_Su009_C" ||  // Item Bag (Medium)
						   ClassName == "BP_Su010_C" ||  // Item Bag (Large)
						   ClassName == "BP_Su011_C" ||  // Level Up Card
						   ClassName == "BP_Su012_C" ||  // Item Box
						   ClassName == "BP_Su015_C" ||  // Team Enhancement Kit
						   ClassName == "BP_Su016_C" ||  // Item Box (Small)
						   ClassName == "BP_Su017_C" ||  // Item Box (Large)
						   ClassName == "BP_Su018_C" ||  // Item Box (Gold)
						   ClassName == "BP_Su020_C" ||  // Revive Card (1/3)
						   ClassName == "BP_Su021_C" ||  // Revive Card (Full)
						   ClassName == "BP_Su026_C" ||  // Team Support Drink
						   ClassName == "BP_AbilitySupplyAlpha_C" ||  // Ability Card (A)
						   ClassName == "BP_AbilitySupplyBeta_C" ||   // Ability Card (B)
						   ClassName == "BP_AbilitySupplyGamma_C");   // Ability Card (Y)
			
			if (!isCharacter && !isNPC && !isItem)
				continue;
			
			// Cache this actor
			CachedActor cachedActor;
			cachedActor.ActorPtr = Actor;
			cachedActor.ClassName = ClassName;
			cachedActor.Position = Actor->K2_GetActorLocation();
			cachedActor.IsMySelf = (Actor == localPlayerPawn) || SDK_GetCharacterOutGameIsMySelf(Actor);
			cachedActor.IsVisible = SDK_IsActorRenderVisible(Actor);  // render-visibility gate
			cachedActor.CitizenType = 0;
			
			// DETECT LOCAL PLAYER - Update cached team ID when we find ourselves
			if (cachedActor.IsMySelf && isBattleCharacter)
			{
				uint8 myTeam = GetCharacterTeamId(Actor);
				if (myTeam != 255)  // Valid team ID
				{
					g_MyTeamId = myTeam;
					g_LastLocalPlayerCharacter = Actor;
				}
			}
			
			// Get character ID and costume (only for CharacterOutGame)
			if (isOutGameCharacter)
			{
				cachedActor.CharacterID = SDK_GetCharacterOutGameId(Actor);
				cachedActor.CostumeCode = SDK_GetCharacterOutGameCostumeCode(Actor);
				cachedActor.Health = 0.0f;
				cachedActor.MaxHealth = 0.0f;
				cachedActor.GuardPoint = 0.0f;
				cachedActor.MaxGuardPoint = 0.0f;
				cachedActor.TeamId = 255;
				cachedActor.IsBot = false;
				cachedActor.IsAlly = false;
			}
			else if (isBattleCharacter)
			{
				cachedActor.CharacterID = 0;
				cachedActor.CostumeCode = -1;
				
				// Retrieve combat properties via SDK helpers
				cachedActor.Health = GetCharacterHealth(Actor);
				cachedActor.MaxHealth = GetCharacterMaxHealth(Actor);
				cachedActor.GuardPoint = GetCharacterGuardPoint(Actor);
				cachedActor.MaxGuardPoint = GetCharacterMaxGuardPoint(Actor);
				cachedActor.TeamId = GetCharacterTeamId(Actor);
				cachedActor.IsBot = IsCharacterBot(Actor);
				
				// Determine if ally (same team as me)
				cachedActor.IsAlly = IsAlly(cachedActor.TeamId);
			}
			else if (ClassName == "NPCCitizen")
			{
				cachedActor.CharacterID = 0;
				cachedActor.CostumeCode = -1;
				cachedActor.Health = 0.0f;
				cachedActor.MaxHealth = 0.0f;
				cachedActor.GuardPoint = 0.0f;
				cachedActor.MaxGuardPoint = 0.0f;
				cachedActor.TeamId = 255;
				cachedActor.IsBot = false;
				cachedActor.IsAlly = false;
				
				// Read NPC citizen type from SDK offset 0x0310 (ECitizenType)
				try
				{
					cachedActor.CitizenType = *(uint8*)(reinterpret_cast<uintptr_t>(Actor) + 0x0310);
				}
				catch (...)
				{
					cachedActor.CitizenType = 0;
				}
			}
			else
			{
				cachedActor.CharacterID = 0;
				cachedActor.CostumeCode = -1;
				cachedActor.Health = 0.0f;
				cachedActor.MaxHealth = 0.0f;
				cachedActor.GuardPoint = 0.0f;
				cachedActor.MaxGuardPoint = 0.0f;
				cachedActor.TeamId = 255;
				cachedActor.IsBot = false;
				cachedActor.IsAlly = false;
			}
			
			// SEPARATE ITEMS FROM ACTORS
			if (isItem)
			{
				newItemList.push_back(cachedActor);
			}
			else
			{
				newActorList.push_back(cachedActor);
			}
		}
		
		const bool extractSkeletonData = SDK_ShouldCacheSkeletonData();

		int skeletonCount = 0;
		if (extractSkeletonData)
		{
			for (auto& cachedActor : newActorList)
			{
				// Extract bones for battle targets and lobby/outgame characters.
				// Aimbot target selection remains battle-only below.
				const bool shouldExtractSkeleton =
					((SDK_IsBattleCharacterClassName(cachedActor.ClassName) &&
					  cachedActor.TeamId != 255 &&
					  !cachedActor.IsMySelf) ||
					 SDK_IsOutGameCharacterClassName(cachedActor.ClassName));
				if (!shouldExtractSkeleton)
					continue;

				if (cachedActor.ActorPtr)
				{
					try
					{
						FVector headWorldPosition = FVector(0, 0, 0);
						cachedActor.Skeleton = SDK_GetBones(cachedActor.ActorPtr, &headWorldPosition);
						cachedActor.HasValidSkeleton = (cachedActor.Skeleton.Head.x > 0 && cachedActor.Skeleton.Head.y > 0);
						cachedActor.HeadWorldPosition = headWorldPosition;
						cachedActor.HasValidHeadWorldPosition =
							cachedActor.HasValidSkeleton &&
							SDK_IsValidHeadWorldPosition(cachedActor.ActorPtr, cachedActor.HeadWorldPosition);
						
						if (cachedActor.HasValidSkeleton && cachedActor.HasValidHeadWorldPosition)
						{
							skeletonCount++;
						}
					}
					catch (...)
					{
						// Skeleton extraction failed - leave HasValidSkeleton = false
						cachedActor.HasValidSkeleton = false;
						cachedActor.HeadWorldPosition = FVector(0, 0, 0);
						cachedActor.HasValidHeadWorldPosition = false;
					}
				}
			}
		}
		if (skeletonCount > 0)
		{
			// Debug logging removed for performance
		}
		
		// Swap buffers (thread-safe double-buffering like zero1's EntityList + EntityList2)
		{
			std::lock_guard<std::mutex> lock(g_ActorCacheMutex);
			g_ActorsToProcess.swap(newActorList);
			g_ActorsForRendering.swap(g_ActorsToProcess);
		}
		
		// Swap item buffers separately
		{
			std::lock_guard<std::mutex> lock(g_ItemsCacheMutex);
			g_ItemsToProcess.swap(newItemList);
			g_ItemsForRendering.swap(g_ItemsToProcess);
		}
	}
	catch (...)
	{
		// Silently fail - will retry in 200ms
	}
}

/**
 * @brief Draw ESP boxes and labels from cached actors (OPTIMIZED - no enumeration per frame)
 */
static void SDK_DrawCachedActors()
{
	// Check if ESP is globally enabled
	if (!ImGuiMenu::g_Settings.EnablePlayerESP)
		return;
	
	// Lock briefly to copy the cached actor list
	std::vector<CachedActor> actorsToRender;
	{
		std::lock_guard<std::mutex> lock(g_ActorCacheMutex);
		actorsToRender = g_ActorsForRendering;  // Copy (fast because not enumeration)
	}
	
	// Now process renders without holding lock (like zero1's pattern)
	for (const CachedActor& cachedActor : actorsToRender)
	{
		try
		{
			AActor* Actor = cachedActor.ActorPtr;
			
			// Verify actor still exists (safety check)
			if (!Actor || Actor->IsDefaultObject())
				continue;
			
			const bool isOutGameCharacter = SDK_IsOutGameCharacterClassName(cachedActor.ClassName);
			const bool isBattleCharacter = SDK_IsBattleCharacterClassName(cachedActor.ClassName);
			
			// Filter by actor type based on menu settings
			if (isOutGameCharacter)
			{
				// This is a lobby character (out of game)
				if (!ImGuiMenu::g_Settings.ShowLobbyCharacters)
					continue;
			}
			else if (isBattleCharacter)
			{
				// This is a battle character (in game) - includes ChXXX patterns
			}
			
			// Filter by actor type based on menu settings
			if (isOutGameCharacter)
			{
				// This is a lobby character (out of game)
				if (!ImGuiMenu::g_Settings.ShowLobbyCharacters)
					continue;
			}
			else if (isBattleCharacter)
			{
				// This is a battle character (in game) - includes ChXXX patterns
				// Check what to show: enemies OR team (self + allies)
				bool isEnemyPlayer = !cachedActor.IsMySelf && !cachedActor.IsAlly;
				bool isTeamMember = cachedActor.IsMySelf || cachedActor.IsAlly;
				
				// Skip if neither ShowEnemies nor ShowTeam is enabled
				if (!ImGuiMenu::g_Settings.ShowEnemies && !ImGuiMenu::g_Settings.ShowTeam)
					continue;
				
				// If ShowEnemies is on, show enemies
				if (ImGuiMenu::g_Settings.ShowEnemies && isEnemyPlayer)
				{
					// Show enemies - continue rendering
				}
				// If ShowTeam is on, show team members
				else if (ImGuiMenu::g_Settings.ShowTeam && isTeamMember)
				{
					// Show team - continue rendering
				}
				// Otherwise skip this actor
				else
				{
					continue;
				}
			}
			else
			{
				// Not a character or battle actor - skip (e.g., NPCCitizen handled separately)
				continue;
			}
			
			// TEAM FILTERING: Skip if team ID doesn't match requirements
			// For now, show all teams (you can add UI toggles later for filtering by team)
			// Example: if (cachedActor.TeamId != 0) continue;  // Only show team 0
			
			// Skip bots if desired (can add UI toggle for this)
			// if (cachedActor.IsBot) continue;
			
			// Skip self if not enabled
			if (cachedActor.IsMySelf)
			{
				// You can add UI toggle: if (!showLocalPlayer) continue;
			}

			// Keep actor discovery cached, but refresh live transform data every
			// frame so fast movement does not leave ESP boxes behind the target.
			FVector framePosition = cachedActor.Position;
			try
			{
				framePosition = Actor->K2_GetActorLocation();
			}
			catch (...)
			{
				continue;
			}

			Bones frameSkeleton = cachedActor.Skeleton;
			bool hasFrameSkeleton = cachedActor.HasValidSkeleton;
			if (ImGuiMenu::g_Settings.ShowPlayerSkeleton)
			{
				try
				{
					frameSkeleton = SDK_GetBones(Actor);
					hasFrameSkeleton = (frameSkeleton.Head.x > 0.0f && frameSkeleton.Head.y > 0.0f);
				}
				catch (...)
				{
					frameSkeleton = cachedActor.Skeleton;
					hasFrameSkeleton = cachedActor.HasValidSkeleton;
				}
			}
			
			// Calculate distance (in UE4 cm units) and check max draw distance
			float distanceCm = SDK_GetDistanceToPosition(framePosition);
			float distanceMeters = distanceCm * 0.01f;  // Convert to meters for comparison/display
			
			if (distanceMeters > ImGuiMenu::g_Settings.Player_DrawDistance)
				continue;  // Skip actors beyond max draw distance
			
			// Project head and feet (like zero1)
			FVector HeadPos = framePosition;
			HeadPos.Z += 80.8f;
			
			FVector FeetPos = framePosition;
			FeetPos.Z -= 85.95f;
			
			FVector2D HeadScreenPos = { 0.0f, 0.0f };
			FVector2D FeetScreenPos = { 0.0f, 0.0f };
			
			bool HeadProjected = SDK_ProjectWorldToScreen(HeadPos, &HeadScreenPos);
			bool FeetProjected = SDK_ProjectWorldToScreen(FeetPos, &FeetScreenPos);
			
			if (!FeetProjected || !HeadProjected)
				continue;
			
			// Calculate box dimensions
			float projectedHeight = FeetScreenPos.Y - HeadScreenPos.Y;
			float boxWidth = (projectedHeight / 4.5f) * 1.3f;
			if (projectedHeight < 30.0f) projectedHeight = 30.0f;
			if (boxWidth < 20.0f) boxWidth = 20.0f;
			
			// Determine box color based on team and status
			ImU32 drawColor = ImGui::GetColorU32(ImVec4(1.0f, 0.0f, 0.0f, 1.0f));  // Red default (enemies)
			
			if (cachedActor.IsMySelf)
			{
				drawColor = ImGui::GetColorU32(ImVec4(0.0f, 1.0f, 0.0f, 1.0f));  // Green for self
			}
			else if (cachedActor.IsAlly)
			{
				drawColor = ImGui::GetColorU32(ImVec4(0.0f, 0.5f, 1.0f, 1.0f));  // Cyan for allies
			}
			else if (cachedActor.IsBot)
			{
				drawColor = ImGui::GetColorU32(ImVec4(1.0f, 1.0f, 0.0f, 1.0f));  // Yellow for enemy bots
			}
			// else: Red for enemy players (default)
			
			// Create rectangle adapted to skeleton (use all 22 bones for accurate bounding box)
			float minX = FLT_MAX;
			float maxX = FLT_MIN;
			float minY = FLT_MAX;
			float maxY = FLT_MIN;
			
			// Check all 22 skeleton bones to find true bounding box
			if (hasFrameSkeleton)
			{
				const Bones& bones = frameSkeleton;
				
				// All 22 bones
				ImVec2 bonePositions[] = {
					bones.Head, bones.Neck, bones.Spine3, bones.Spine2, bones.Spine1, bones.Spine0,
					bones.LClavicle, bones.LUpperArm, bones.LForeArm, bones.LHand,
					bones.RClavicle, bones.RUpperArm, bones.RForeArm, bones.RHand,
					bones.LTight, bones.LCalf, bones.LFoot, bones.LToe,
					bones.RTight, bones.RCalf, bones.RFoot, bones.RToe
				};
				
				// Find min/max from all bone positions
				for (int i = 0; i < 22; i++)
				{
					if (bonePositions[i].x > 0.0f && bonePositions[i].y > 0.0f)  // Valid screen position
					{
						if (bonePositions[i].x < minX) minX = bonePositions[i].x;
						if (bonePositions[i].x > maxX) maxX = bonePositions[i].x;
						if (bonePositions[i].y < minY) minY = bonePositions[i].y;
						if (bonePositions[i].y > maxY) maxY = bonePositions[i].y;
					}
				}
				
				// If all bones are invalid, fallback to FLT_MAX init
				if (minX == FLT_MAX || maxX == FLT_MIN)
				{
					minX = FeetScreenPos.X - boxWidth;
					maxX = FeetScreenPos.X + boxWidth;
					minY = FeetScreenPos.Y;
					maxY = HeadScreenPos.Y;
				}
				else
				{
					// Add small padding to the bounding box
					float paddingX = (maxX - minX) * 0.05f;
					float paddingY = (maxY - minY) * 0.05f;
					minX -= paddingX;
					maxX += paddingX;
					minY -= paddingY;
					maxY += paddingY;
					
					// Ensure min < max (swap if inverted)
					if (minX > maxX) std::swap(minX, maxX);
					if (minY > maxY) std::swap(minY, maxY);
				}
			}
			else
			{
				// Fallback: use old method if skeleton not valid
				minX = FeetScreenPos.X - boxWidth;
				maxX = FeetScreenPos.X + boxWidth;
				minY = FeetScreenPos.Y;
				maxY = HeadScreenPos.Y;
			}
			
			// Distance already calculated for max draw distance check above
			
			// Queue rectangle
			Rect2D rect;
			rect.minX = minX;
			rect.minY = minY;
			rect.maxX = maxX;
			rect.maxY = maxY;
			rect.color = drawColor;
			rect.distance = distanceCm;  // Keep in UE4 cm for font sizing (like zero1)
			rect.health = cachedActor.Health;
			rect.maxHealth = cachedActor.MaxHealth;
			rect.guardPoint = cachedActor.GuardPoint;
			rect.maxGuardPoint = cachedActor.MaxGuardPoint;
			
			// Only call PlayerState-dependent functions for battle characters (not CharacterOutGame)
			if (isBattleCharacter)
			{
				rect.plusUltra = GetCharacterPlusUltra(Actor);
				rect.maxPlusUltra = rect.plusUltra > 0.0f ? 100.0f : 0.0f;  // Assume max 100 for PU
				rect.isDying = GetCharacterIsDying(Actor);
				rect.platform = GetCharacterPlatform(Actor);
			}
			else
			{
				// CharacterOutGame doesn't have valid PlayerState
				rect.plusUltra = 0.0f;
				rect.maxPlusUltra = 0.0f;
				rect.isDying = false;
				rect.platform = 0;
			}
			
			{
				std::lock_guard<std::mutex> lock(g_RectMutex);
				if (g_RectsToDraw.size() < MAX_ESP_BOXES)
					g_RectsToDraw.push_back(rect);
			}
			
			// Queue actor name text with team ID and health info
			try
			{
				const char* playerName = SDK_GetActorDisplayName(Actor, cachedActor.IsMySelf, false);
				std::string displayText = playerName ? playerName : "Unknown";
				
				// Add platform if enabled (only for battle characters with valid PlayerState)
				if (ImGuiMenu::g_Settings.ShowPlatform && 
					isBattleCharacter)
				{
					uint8 platform = GetCharacterPlatform(Actor);
					const char* platformStr;
					switch (platform) {
						case 1: platformStr = " PS"; break;
						case 2: platformStr = " XB"; break;
						case 3: platformStr = " PC"; break;
						case 4: platformStr = " SW"; break;
						default: platformStr = ""; break;
					}
					displayText += platformStr;
				}
				
// Add team ID if valid and enabled
			if (ImGuiMenu::g_Settings.ShowTeamId && cachedActor.TeamId < 255)
				{
					displayText += " Team" + std::to_string(cachedActor.TeamId) + "";
				}
				
				// Add ally/bot indicator
				if (cachedActor.IsAlly && !cachedActor.IsMySelf)
				{
					displayText += " Me";
				}
				else if (cachedActor.IsBot)
				{
					displayText += " [BOT]";
				}
				
				if (!displayText.empty())
				{
					TextLabel label;
					label.x = (minX + maxX) / 2.0f;  // Center horizontally on adaptive box
					label.y = minY - 10.0f;         // Above the box top
					label.distance = distanceCm;  // Distance in UE4 cm for font sizing formula (like zero1)
					label.color = drawColor;
					label.text = displayText;
					
					{
						std::lock_guard<std::mutex> lock(g_TextMutex);
						if (g_TextToDraw.size() < MAX_ESP_BOXES)
							g_TextToDraw.push_back(label);
					}
				}
			}
			catch (...)
			{
				// Silently ignore name errors
			}
		}
		catch (...)
		{
			// Silently ignore draw errors
		}
	}
	
	// ===== NPC/KOTA RENDERING (NO BOXES, JUST TEXT) =====
	// Draw NPCCitizen actors with special handling
	for (const CachedActor& cachedActor : actorsToRender)
	{
		try
		{
			// Only process NPCCitizen
			if (cachedActor.ClassName != "NPCCitizen")
				continue;
			
			// Only show if SPECIAL_KID (citizenType == 4)
			if (cachedActor.CitizenType != 4)
				continue;
			
			// Skip if KOTA display disabled
			if (!ImGuiMenu::g_Settings.ShowKota)
				continue;
			
			AActor* Actor = cachedActor.ActorPtr;
			if (!Actor || Actor->IsDefaultObject())
				continue;
			
			// Calculate distance (in UE4 cm units, no filtering for KOTA)
			float distanceCm = SDK_GetDistanceToPosition(cachedActor.Position);
			float distanceMeters = distanceCm * 0.01f;  // Convert to meters for display only
			
			// Project to screen
			FVector2D screenPos = { 0.0f, 0.0f };
			if (!SDK_ProjectWorldToScreen(cachedActor.Position, &screenPos))
				continue;
			
			// Create text label for KOTA
			try
			{
				std::string displayText = "KOTA";
				
				// Add distance
				char distStr[32];
				snprintf(distStr, sizeof(distStr), " [%.1fm]", distanceMeters);  // Display in meters
				displayText += distStr;
				
				if (!displayText.empty())
				{
					TextLabel label;
					label.x = screenPos.X;
					label.y = screenPos.Y;
					label.distance = distanceCm;  // Distance in UE4 cm (not used with isFixedSize)
					label.color = IM_COL32(200, 100, 200, 255);  // Magenta for NPCs
					label.text = displayText;
					label.isFixedSize = true;  // Fixed size - always visible
					
					{
						std::lock_guard<std::mutex> lock(g_TextMutex);
						if (g_TextToDraw.size() < MAX_ESP_BOXES)
							g_TextToDraw.push_back(label);
					}
				}
			}
			catch (...)
			{
				// Silently ignore NPC label errors
			}
		}
		catch (...)
		{
			// Silently ignore NPC draw errors
		}
	}
}

