static void ResetAimbotState()
{
	g_CurrentAimbotTarget = AimbotTarget();
	g_LastAimbotTargetPtr = nullptr;
	g_LastSmoothedAimbotTargetPtr = nullptr;
	g_LastAimbotTargetTime = 0;
}

static bool IsAimbotHotkeyActive()
{
	bool keyboardPressed = false;
	bool gamepadPressed = false;

	try
	{
		keyboardPressed = IsKeyPressed(ImGuiMenu::g_Settings.AimbotHoldKey.Keyboard, HotKeyType::KeyboardMouse);
		if (!ImGuiMenu::IsVisible())
		{
			gamepadPressed =
				IsKeyPressed(ImGuiMenu::g_Settings.AimbotHoldKey.Xbox, HotKeyType::Gamepad) ||
				IsKeyPressed(ImGuiMenu::g_Settings.AimbotHoldKey.PS4, HotKeyType::Gamepad);
		}
	}
	catch (...)
	{
		return false;
	}

	return keyboardPressed || gamepadPressed;
}

static bool IsUsableAimbotTarget(const AimbotTarget& target)
{
	if (!target.isValid || target.isAlly || !target.actorPtr)
		return false;
	if (!SDK_IsReadableActor(target.actorPtr))
		return false;
	if (SDK_IsZeroVector(target.aimWorldPosition) || !SDK_IsFiniteVector(target.aimWorldPosition))
		return false;
	return true;
}

static FVector GetSafeActorVelocity(AActor* actor)
{
	if (!SDK_IsReadableActor(actor))
		return FVector(0, 0, 0);

	try
	{
		const FVector velocity = actor->GetVelocity();
		if (SDK_IsFiniteVector(velocity))
			return velocity;
	}
	catch (...)
	{
	}

	return FVector(0, 0, 0);
}

static bool ApplyAimbotControlRotation(APlayerController* playerController, const FVector& aimAngles, AActor* targetActor)
{
	if (!playerController || !SDK_IsReadableMemory(playerController, sizeof(void*)))
		return false;
	if (!SDK_IsFiniteVector(aimAngles))
		return false;

	try
	{
		float targetPitch = aimAngles.X;
		float targetYaw = aimAngles.Y;

		if (targetPitch > 89.0f) targetPitch = 89.0f;
		if (targetPitch < -89.0f) targetPitch = -89.0f;

		float smoothFactor = ImGuiMenu::g_Settings.AimbotSmoothFactor;
		if (!std::isfinite(smoothFactor)) smoothFactor = 1.0f;
		if (smoothFactor < 0.01f) smoothFactor = 0.01f;
		if (smoothFactor > 10.0f) smoothFactor = 10.0f;
		const float smoothStep = (smoothFactor <= 1.0f) ? smoothFactor : (1.0f / smoothFactor);

		if (g_LastSmoothedAimbotTargetPtr == nullptr)
		{
			const FRotator currentRotation = playerController->GetControlRotation();
			const FVector currentAngles(currentRotation.Pitch, currentRotation.Yaw, currentRotation.Roll);
			if (SDK_IsFiniteVector(currentAngles))
				g_LastAppliedAimAngles = currentRotation;
			else
				g_LastAppliedAimAngles = FRotator(targetPitch, targetYaw, 0.0f);
		}

		const bool targetChanged =
			g_LastSmoothedAimbotTargetPtr != nullptr &&
			g_LastSmoothedAimbotTargetPtr != targetActor;

		if (ImGuiMenu::g_Settings.AimbotSmoothing && !targetChanged)
		{
			targetPitch = SmoothDampAngle(g_LastAppliedAimAngles.Pitch, targetPitch, smoothStep);
			targetYaw = SmoothDampAngle(g_LastAppliedAimAngles.Yaw, targetYaw, smoothStep);
		}

		if (targetPitch > 89.0f) targetPitch = 89.0f;
		if (targetPitch < -89.0f) targetPitch = -89.0f;

		const FRotator newRotation(targetPitch, targetYaw, 0.0f);
		playerController->SetControlRotation(newRotation);

		g_LastAppliedAimAngles = newRotation;
		g_LastSmoothedAimbotTargetPtr = targetActor;
		g_LastAimbotTargetTime = GetCurrentTimeMs();
		return true;
	}
	catch (...)
	{
		return false;
	}
}

extern "C" SDK::AActor* SDK_GetBulletTPFOVTargetWithPosition(FVector* OutTargetPosition)
{
	if (OutTargetPosition)
		*OutTargetPosition = FVector(0, 0, 0);

	if (ImGuiMenu::g_Settings.EnableAimbot && SDK_IsReadableActor(g_LastAimbotTargetPtr))
	{
		try
		{
			std::unique_lock<std::mutex> lock(g_ActorCacheMutex, std::try_to_lock);
			if (lock.owns_lock())
			{
				for (const auto& actor : g_ActorsForRendering)
				{
					if (actor.ActorPtr == g_LastAimbotTargetPtr &&
						SDK_IsBattleCharacterClassName(actor.ClassName) &&
						actor.TeamId != 255 &&
						!actor.IsMySelf &&
						!actor.IsAlly &&
						(!ImGuiMenu::g_Settings.BulletTPIgnoreDownedTargets || !IsCharacterDowned(actor.ActorPtr)) &&
						actor.HasValidHeadWorldPosition &&
						!SDK_IsZeroVector(actor.HeadWorldPosition) &&
						SDK_IsFiniteVector(actor.HeadWorldPosition))
					{
						if (OutTargetPosition)
							*OutTargetPosition = actor.HeadWorldPosition;
						return g_LastAimbotTargetPtr;
					}
				}
			}
		}
		catch (...)
		{
		}
	}

	AimbotTarget target = SelectSilentAimTarget();
	if (!target.isValid ||
		SDK_IsZeroVector(target.aimWorldPosition) ||
		!SDK_IsFiniteVector(target.aimWorldPosition))
		return nullptr;

	if (OutTargetPosition)
		*OutTargetPosition = target.aimWorldPosition;

	return target.actorPtr;
}

extern "C" SDK::AActor* SDK_GetBulletTPFOVTarget()
{
	return SDK_GetBulletTPFOVTargetWithPosition(nullptr);
}

extern "C" FVector SDK_GetLocalPlayerVelocity()
{
	APlayerController* playerController = SDK_GetPlayerController();
	if (!playerController || !SDK_IsReadableMemory(playerController, sizeof(void*)))
		return FVector(0, 0, 0);

	APawn* playerPawn = nullptr;
	if (!SDK_TryReadMemory(&playerController->Pawn, playerPawn) ||
		!SDK_IsReadableMemory(playerPawn, sizeof(void*)))
	{
		SDK_TryReadMemory(&playerController->AcknowledgedPawn, playerPawn);
	}

	if (!SDK_IsReadableMemory(playerPawn, sizeof(void*)))
		return FVector(0, 0, 0);

	try
	{
		if (playerPawn->IsA(ACharacter::StaticClass()))
		{
			ACharacter* playerCharacter = static_cast<ACharacter*>(playerPawn);
			UCharacterMovementComponent* movement = nullptr;
			if (SDK_TryReadMemory(&playerCharacter->CharacterMovement, movement) &&
				SDK_IsReadableMemory(movement, sizeof(UMovementComponent)))
			{
				FVector movementVelocity = FVector(0, 0, 0);
				if (SDK_TryReadMemory(&movement->Velocity, movementVelocity) &&
					SDK_IsFiniteVector(movementVelocity))
				{
					return movementVelocity;
				}
			}
		}

		const FVector actorVelocity = playerPawn->GetVelocity();
		if (SDK_IsFiniteVector(actorVelocity))
			return actorVelocity;
	}
	catch (...)
	{
	}

	return FVector(0, 0, 0);
}

/**
 * @brief Log BulletTP debug info to file
 */
static inline void BulletTPLog(const char* format, ...)
{
	(void)format;
}

/**
 * @brief Main aimbot tick function
 */
extern "C" void SDK_RunAimbot()
{
	try
	{
		if (!ImGuiMenu::g_Settings.EnableAimbot || IsGameActive() == false)
		{
			ResetAimbotState();
			return;
		}

		if (!IsAimbotHotkeyActive())
		{
			ResetAimbotState();
			return;
		}

		APlayerController* playerController = SDK_GetPlayerController();
		if (!playerController || !SDK_IsReadableMemory(playerController, sizeof(void*)))
		{
			ResetAimbotState();
			return;
		}

		FVector cameraPos = SDK_GetCameraLocation();
		if (SDK_IsZeroVector(cameraPos) || !SDK_IsFiniteVector(cameraPos))
		{
			ResetAimbotState();
			return;
		}

		AimbotTarget target = SelectAimbotTarget();
		if (!IsUsableAimbotTarget(target))
		{
			ResetAimbotState();
			return;
		}

		FVector aimWorldPos = target.aimWorldPosition;
		const FVector targetVelocity = GetSafeActorVelocity(target.actorPtr);
		const FVector localVelocity = SDK_GetLocalPlayerVelocity();
		const FVector predictionVelocity = targetVelocity - localVelocity;

		if (ImGuiMenu::g_Settings.AimbotSmoothing &&
			SDK_IsFiniteVector(predictionVelocity) &&
			!SDK_IsZeroVector(predictionVelocity))
		{
			const FVector deltaPos = target.aimWorldPosition - cameraPos;
			const float distance = sqrtf(deltaPos.X * deltaPos.X + deltaPos.Y * deltaPos.Y + deltaPos.Z * deltaPos.Z);
			float leadTime = distance / 18000.0f;
			if (!std::isfinite(leadTime) || leadTime < 0.0f)
				leadTime = 0.0f;
			if (leadTime > 0.35f)
				leadTime = 0.35f;

			const FVector predictedPos = target.aimWorldPosition + (predictionVelocity * leadTime);
			if (!SDK_IsZeroVector(predictedPos) && SDK_IsFiniteVector(predictedPos))
				aimWorldPos = predictedPos;
		}

		const FVector aimAngles = CalculateAimAngles_Method0(cameraPos, aimWorldPos);
		if (!SDK_IsFiniteVector(aimAngles) ||
			!ApplyAimbotControlRotation(playerController, aimAngles, target.actorPtr))
		{
			ResetAimbotState();
			return;
		}
	}
	catch (...)
	{
		ResetAimbotState();
	}
}

/**
 * @brief Check if bullet name matches Alpha skill patterns (like Zero1)
 * Alpha skills: Unique1, CementShot, Cracker, FogShot, etc.
 */
static bool IsAlphaSkillBullet(const std::string& bulletName)
{
	if (bulletName.empty())
		return false;
	
	// Alpha patterns from Zero1 analysis
	const char* alphaPatterns[] = {
		"Unique1",           // Generic Alpha marker
		"BPB_CementShot",    // Cement skill
		"BPB_Cement_L",      // Cement variant
		"BPB_Cracks_L",      // Cracker skill
		"BPB_FogShot_",      // Fog skill
		"BPB202_U1_",        // Character-specific Alpha
		nullptr
	};
	
	// Check if any pattern matches
	for (int i = 0; alphaPatterns[i] != nullptr; i++)
	{
		if (bulletName.find(alphaPatterns[i]) != std::string::npos)
			return true;
	}
	
	return false;
}

/**
 * @brief Get class name from UObject (usually at offset 0x18 or via VTable)
 * Simplified: reads class name for bullet type identification
 */
static std::string GetActorClassName(AActor* actor)
{
	if (!actor || !IsValidAddress((uintptr_t)actor))
		return "";
	
	try
	{
		// Get class pointer (at offset 0 in UObject)
		uintptr_t classPtr = *(uintptr_t*)actor;
		if (!IsValidAddress(classPtr))
			return "";
		
		// Get class name from class object (offset 0x18 for FName)
		uintptr_t classNameAddr = classPtr + 0x18;
		char nameBuffer[256] = {0};
		
		// Try to read name
		memcpy(nameBuffer, (void*)classNameAddr, sizeof(nameBuffer) - 1);
		
		return std::string(nameBuffer);
	}
	catch (...)
	{
		return "";
	}
}

/**
 * @brief Silent Aim (Bullet TP) for Alpha Skills - teleports bullets to target
 * Uses Zero1's direct bullet position teleportation technique with Alpha filtering
 */
extern "C" void SDK_RunSilentAim()
{
	// Check if bullet tp enabled
	if (!ImGuiMenu::g_Settings.EnableBulletTP)
		return;
	
	if (IsGameActive() == false)
		return;
	
	BulletTPLog("===== BULLETTP TICK START =====");
	
	// Get player controller
	APlayerController* playerController = SDK_GetPlayerController();
	if (!playerController || !playerController->Pawn)
	{
		BulletTPLog("ERROR: No player controller or pawn");
		return;
	}
	
	// Get player pawn (for bullet enumeration)
	ACharacter* playerPawn = (ACharacter*)playerController->Pawn;
	
	// Enumerate bullets from player (OwningBullets TArray at offset 2512 - like Zero1)
	std::vector<AActor*> bullets = GetOwningBullets(playerPawn);
	
	char logMsg[256];
	snprintf(logMsg, sizeof(logMsg), "[BulletTP] Found %d bullets from player", (int)bullets.size());
	BulletTPLog("Found %d bullets from player", (int)bullets.size());
	
	if (bullets.empty())
	{
		BulletTPLog("No bullets found - returning");
		return;
	}
	
	// Get camera location for target selection
	FVector cameraPos = SDK_GetCameraLocation();
	if (cameraPos.X == 0 && cameraPos.Y == 0 && cameraPos.Z == 0)
	{
		BulletTPLog("ERROR: Invalid camera position");
		return;
	}
	
	char camLog[256];
	snprintf(camLog, sizeof(camLog), "[BulletTP] Camera pos: (%.1f, %.1f, %.1f)", cameraPos.X, cameraPos.Y, cameraPos.Z);
	BulletTPLog("Camera pos: (%.1f, %.1f, %.1f)", cameraPos.X, cameraPos.Y, cameraPos.Z);
	
	// Select target using Silent Aim FOV settings
	AimbotTarget target = SelectSilentAimTarget();
	if (!target.isValid)
	{
		BulletTPLog("ERROR: No valid target found in FOV");
		return;
	}
	
	char targetLog[256];
	snprintf(targetLog, sizeof(targetLog), "[BulletTP] Target found: %s", 
		target.className.empty() ? "NULL" : target.className.c_str());
	BulletTPLog("Target found: %s", target.className.empty() ? "NULL" : target.className.c_str());
	
	// Validate target still exists
	{
		std::lock_guard<std::mutex> lock(g_ActorCacheMutex);
		bool targetStillValid = false;
		for (auto& actor : g_ActorsForRendering)
		{
			if (actor.ActorPtr == target.actorPtr)
			{
				targetStillValid = true;
				break;
			}
		}
		if (!targetStillValid)
		{
			BulletTPLog("ERROR: Target no longer in actor cache");
			g_LastSilentAimTargetPtr = nullptr;
			return;
		}
	}
	
	if (ImGuiMenu::g_Settings.BulletTPIgnoreDownedTargets && IsCharacterDowned(target.actorPtr))
	{
		BulletTPLog("ERROR: Target is downed");
		return;
	}
	
	if (target.isAlly)
	{
		BulletTPLog("ERROR: Target is ally");
		return;
	}
	
	FVector targetBonePos = target.aimWorldPosition;
	
	// Fallback if bone position is invalid
	if (targetBonePos.X == 0 && targetBonePos.Y == 0 && targetBonePos.Z == 0)
	{
		BulletTPLog("Invalid target bone position");
		return;
	}
	
	char headLog[256];
	snprintf(headLog, sizeof(headLog), "[BulletTP] Target head bone pos: (%.1f, %.1f, %.1f)", 
		targetBonePos.X, targetBonePos.Y, targetBonePos.Z);
	BulletTPLog("Target head bone pos: (%.1f, %.1f, %.1f)", targetBonePos.X, targetBonePos.Y, targetBonePos.Z);
	
	// Process each bullet - TELEPORT TO TARGET (like Zero1)
	static std::vector<AActor*> processedBullets;  // Track which bullets we've processed this frame
	
	int bulletsProcessed = 0;
	int bulletsIgnored = 0;
	
	char procLog[256];
	snprintf(procLog, sizeof(procLog), "[BulletTP] Processing %d bullets...", (int)bullets.size());
	BulletTPLog("Processing %d bullets...", (int)bullets.size());
	
	for (AActor* bullet : bullets)
	{
		if (!bullet)
		{
			BulletTPLog("  - NULL bullet, skipping");
			continue;
		}
		
		// Skip if already processed this frame
		bool alreadyProcessed = false;
		for (AActor* processed : processedBullets)
		{
			if (processed == bullet)
			{
				alreadyProcessed = true;
				break;
			}
		}
		if (alreadyProcessed)
		{
			BulletTPLog("  - Bullet already processed this frame, skipping");
			continue;
		}
		
		try
		{
			// Get bullet class name
			std::string bulletClassName = GetActorClassName(bullet);
			
			char tpLog[256];
			snprintf(tpLog, sizeof(tpLog), "[BulletTP]   - Bullet '%s' TELEPORTING", bulletClassName.c_str());
			BulletTPLog("  - Bullet '%s' TELEPORTING", bulletClassName.c_str());
			
			// Teleport bullet to target bone position 25 times (like Zero1)
			// Offset 464 = USphereComponent.unk_TeleportOff (bullet position)
			TeleportBulletToPosition(bullet, targetBonePos);
			
			// Mark as processed
			processedBullets.push_back(bullet);
			bulletsProcessed++;
		}
		catch (...)
		{
			BulletTPLog("  - Exception caught while processing bullet");
			continue;
		}
	}
	
	char summaryLog[256];
	snprintf(summaryLog, sizeof(summaryLog), "[BulletTP] Summary: %d processed, %d ignored", bulletsProcessed, bulletsIgnored);
	BulletTPLog("Summary: %d processed, %d ignored", bulletsProcessed, bulletsIgnored);
	
	// Clear processed bullets after a short delay
	static int frameCounter = 0;
	frameCounter++;
	if (frameCounter > 5)  // 5 frames = ~83ms at 60 FPS
	{
		processedBullets.clear();
		frameCounter = 0;
	}
	
	BulletTPLog("===== BULLETTP TICK END =====");
}

/**
 * @brief Draw aimbot visualization (crosshair on target)
 */
/**
 * @brief Draw aimbot FOV circle on screen
 */
extern "C" void SDK_DrawAimbotFOV()
{
	ImDrawList* drawlist = ImGui::GetForegroundDrawList();
	if (!drawlist)
		return;

	// Only draw if aimbot enabled and setting is on
	if (!ImGuiMenu::g_Settings.EnableAimbot || !ImGuiMenu::g_Settings.AimbotDrawFOV)
		return;

	float viewportX = 0.0f;
	float viewportY = 0.0f;
	SDK_GetOverlayViewportSize(&viewportX, &viewportY);
	if (viewportX <= 1.0f || viewportY <= 1.0f)
		return;

	float screenCenterX = viewportX / 2.0f;
	float screenCenterY = viewportY / 2.0f;

	float fovRadius = SDK_GetEffectiveFovRadius(ImGuiMenu::g_Settings.AimbotFOVRadius);

	// Draw circle: yellow outline, semi-transparent
	ImU32 fovColor = IM_COL32(255, 225, 40, 180);
	SDK_DrawFovCircle(drawlist, ImVec2(screenCenterX, screenCenterY), fovRadius, fovColor);
}

/**
 * @brief Draw the game crosshair at the center of the screen.
 * Static reticle (cross + center dot) marking the game's aim point.
 */
extern "C" void SDK_DrawCrosshair()
{
	if (!ImGuiMenu::g_Settings.AimbotDrawCrosshair)
		return;

	float viewportX = 0.0f;
	float viewportY = 0.0f;
	SDK_GetOverlayViewportSize(&viewportX, &viewportY);
	if (viewportX <= 1.0f || viewportY <= 1.0f)
		return;

	ImDrawList* drawlist = ImGui::GetForegroundDrawList();
	if (!drawlist)
		return;

	const float cx = viewportX / 2.0f;
	const float cy = viewportY / 2.0f;
	const float gap = 4.0f;    // empty space around the exact center
	const float len = 10.0f;   // arm length
	const float thick = 1.5f;
	const ImU32 col = IM_COL32(0, 255, 0, 230);       // green lines
	const ImU32 outline = IM_COL32(0, 0, 0, 160);     // dark outline for contrast

	// Outline pass (slightly thicker, dark) then colored pass on top.
	for (int pass = 0; pass < 2; ++pass)
	{
		const ImU32 c = (pass == 0) ? outline : col;
		const float t = (pass == 0) ? thick + 1.5f : thick;

		drawlist->AddLine(ImVec2(cx - gap - len, cy), ImVec2(cx - gap, cy), c, t); // left
		drawlist->AddLine(ImVec2(cx + gap, cy), ImVec2(cx + gap + len, cy), c, t); // right
		drawlist->AddLine(ImVec2(cx, cy - gap - len), ImVec2(cx, cy - gap), c, t); // top
		drawlist->AddLine(ImVec2(cx, cy + gap), ImVec2(cx, cy + gap + len), c, t); // bottom
	}

	drawlist->AddCircleFilled(ImVec2(cx, cy), 1.5f, col); // center dot
}

/**
 * @brief Draw bullet redirection FOV circle on screen
 */
extern "C" void SDK_DrawBulletRedirectionFOV()
{
	ImDrawList* drawlist = ImGui::GetForegroundDrawList();
	if (!drawlist)
		return;

	// Only draw if bullet redirection enabled
	if (!ImGuiMenu::g_Settings.EnableBulletTP)
		return;

	float viewportX = 0.0f;
	float viewportY = 0.0f;
	SDK_GetOverlayViewportSize(&viewportX, &viewportY);
	if (viewportX <= 1.0f || viewportY <= 1.0f)
		return;

	float screenCenterX = viewportX / 2.0f;
	float screenCenterY = viewportY / 2.0f;

	float fovRadius = SDK_GetEffectiveFovRadius(ImGuiMenu::g_Settings.BulletTP_FOVRadius);

	// Draw circle: cyan outline, semi-transparent
	ImU32 bulletFovColor = IM_COL32(0, 220, 255, 180);
	SDK_DrawFovCircle(drawlist, ImVec2(screenCenterX, screenCenterY), fovRadius, bulletFovColor);
}

extern "C" void SDK_DrawAimbotInfo()
{
	try
	{
		if (!ImGuiMenu::g_Settings.EnableAimbot || !ImGuiMenu::g_Settings.AimbotDrawLine)
			return;
		
		float viewportX = 0.0f;
		float viewportY = 0.0f;
		SDK_GetOverlayViewportSize(&viewportX, &viewportY);
		if (viewportX <= 1.0f || viewportY <= 1.0f)
			return;

		ImDrawList* drawlist = ImGui::GetForegroundDrawList();
		if (!drawlist)
			return;

		const ImVec2 centerScreen(viewportX / 2.0f, viewportY / 2.0f);
		std::lock_guard<std::mutex> lock(g_ActorCacheMutex);

		for (const auto& cachedActor : g_ActorsForRendering)
		{
			if (!cachedActor.ActorPtr || cachedActor.IsMySelf)
				continue;

			if (!SDK_IsBattleCharacterClassName(cachedActor.ClassName))
				continue;

			if (cachedActor.TeamId == 255 || cachedActor.IsAlly)
				continue;
			
			const ImVec2 headPos = cachedActor.Skeleton.Head;
			if (headPos.x <= 0.0f || headPos.y <= 0.0f ||
				headPos.x > viewportX || headPos.y > viewportY ||
				!std::isfinite(headPos.x) || !std::isfinite(headPos.y))
			{
				continue;
			}
			
			drawlist->AddCircle(headPos, 5.0f, IM_COL32(255, 255, 0, 255), 0, 2.0f);
			drawlist->AddLine(centerScreen, headPos, IM_COL32(255, 255, 0, 200), 1.5f);
		}
	}
	catch (...)
	{
	}
}



/**
 * @brief Teleport to Kota (special NPC) with definable hotkey
 */
extern "C" void SDK_RunTeleportToKota()
{
	static bool lastTeleportToKotaPressed = false;
	static auto lastTeleportToKotaTime = std::chrono::high_resolution_clock::now();
	const int TELEPORT_TO_KOTA_COOLDOWN_MS = 500;

	// Check if teleport enabled
	if (!ImGuiMenu::g_Settings.EnableTeleportToKota)
	{
		lastTeleportToKotaPressed = false;

		// Log only occasionally to avoid spam
		static int frameCounter = 0;
		frameCounter++;
		if (frameCounter > 300)  // Every 5 seconds at 60 FPS
		{
			frameCounter = 0;
		}
		return;
	}
	
	
	// Note: We DON'T check IsGameActive() here because we want to teleport even with menu open
	// (Unlike aimbot which needs to be disabled when menu is visible)
	
	bool menuVisible = ImGuiMenu::IsVisible();
	
	// Check hotkey input (Keyboard/Mouse + Gamepad)
	bool keyboardPressed = IsKeyPressed(ImGuiMenu::g_Settings.TeleportToKotaKey.Keyboard, HotKeyType::KeyboardMouse);
	bool gamepadPressed = false;
	
	if (!menuVisible)
	{
		gamepadPressed = IsKeyPressed(ImGuiMenu::g_Settings.TeleportToKotaKey.Xbox, HotKeyType::Gamepad) ||
						IsKeyPressed(ImGuiMenu::g_Settings.TeleportToKotaKey.PS4, HotKeyType::Gamepad);
	}
	
	bool hotKeyPressed = keyboardPressed || gamepadPressed;
	if (!hotKeyPressed)
	{
		lastTeleportToKotaPressed = false;
		return;  // Hotkey not pressed
	}

	if (lastTeleportToKotaPressed)
	{
		return;
	}

	auto now = std::chrono::high_resolution_clock::now();
	auto elapsed = std::chrono::duration_cast<std::chrono::milliseconds>(now - lastTeleportToKotaTime).count();
	if (elapsed < TELEPORT_TO_KOTA_COOLDOWN_MS)
	{
		lastTeleportToKotaPressed = true;
		return;
	}

	lastTeleportToKotaPressed = true;
	lastTeleportToKotaTime = now;
	
	// Get player controller
	APlayerController* playerController = SDK_GetPlayerController();
	if (!playerController)
	{
		return;
	}
	
	if (!playerController->Pawn)
	{
		return;
	}
	
	
	// Find Kota in actor cache (NPCCitizen with CitizenType == 4)
	CachedActor* kotaActor = nullptr;
	int actorCount = 0;
	{
		std::lock_guard<std::mutex> lock(g_ActorCacheMutex);
		
		actorCount = g_ActorsForRendering.size();
		
		for (auto& actor : g_ActorsForRendering)
		{
			if (!actor.ActorPtr)
			{
				continue;
			}
			
			// Search for NPCCitizen with CitizenType == 4 (SPECIAL_KID)
			if (actor.ClassName == "NPCCitizen" && actor.CitizenType == 4 && !actor.IsMySelf)
			{
				kotaActor = &actor;
				break;
			}
		}
	}
	
	if (!kotaActor)
	{
		return;
	}
	
	// Get Kota's position
	FVector kotaPosition = kotaActor->Position;
	
	if (kotaPosition.X == 0 && kotaPosition.Y == 0 && kotaPosition.Z == 0)
	{
		return;
	}
	
	// Offset height to spawn above ground (avoid stuck)
	kotaPosition.Z += 100.0f;
	
	// Get player pawn
	AActor* playerPawn = playerController->Pawn;
	if (!playerPawn)
	{
		return;
	}
	
	
	// Teleport player to Kota using K2_TeleportTo
	FRotator dummyRotation = FRotator(0, 0, 0);  // Keep current rotation
	bool teleportSuccess = playerPawn->K2_TeleportTo(kotaPosition, dummyRotation);
	
	if (teleportSuccess)
	{
		char logMsg[256];
		snprintf(logMsg, sizeof(logMsg), "[TeleportToKota] SUCCESS: Teleported to Kota at (%.1f, %.1f, %.1f)", 
			kotaPosition.X, kotaPosition.Y, kotaPosition.Z);
		
	}
	else
	{
	}
}

// ===== TELEPORT ITEMS (LEVEL UP CARDS) =====
// Helper function to teleport specific item type
static void TeleportItemType(const std::string& itemClassName, const std::string& itemDisplayName)
{
	try
	{
		if (!ImGuiMenu::g_Settings.EnableTeleportLevelUpCards)
			return;
		
		APlayerController* playerController = SDK_GetPlayerController();
		if (!playerController || !playerController->Pawn)
			return;
		
		AActor* playerPawn = playerController->Pawn;
		FVector playerPos = playerPawn->K2_GetActorLocation();
		FVector forwardVector = playerPawn->GetActorForwardVector();
		
		playerPos = playerPos + (forwardVector * 200.0f);
		playerPos.Z += 100.0f;
		
		std::vector<AActor*> itemsToCopy;
		{
			std::lock_guard<std::mutex> lock(g_ItemsCacheMutex);
			for (auto& cachedActor : g_ItemsForRendering)
			{
				if (cachedActor.ClassName != itemClassName)
					continue;
				
				if (!cachedActor.ActorPtr || (uintptr_t)cachedActor.ActorPtr < 0x10000)
					continue;
				
				try
				{
					if (cachedActor.ActorPtr->IsDefaultObject())
						continue;
				}
				catch (...)
				{
					continue;
				}
				
				itemsToCopy.push_back(cachedActor.ActorPtr);
			}
		}
		
		int count = 0;
		for (auto* actorPtr : itemsToCopy)
		{
			try
			{
				FRotator dummyRotation = FRotator(0, 0, 0);
				if (actorPtr->K2_TeleportTo(playerPos, dummyRotation))
					count++;
			}
			catch (...)
			{
			}
		}
		
		if (count > 0)
		{
			char logMsg[256];
			snprintf(logMsg, sizeof(logMsg), "[TeleportItems] ✓ %s: %d items teleported", itemDisplayName.c_str(), count);
		}
	}
	catch (...)
	{
	}
}

